{"code": "import json

# Load European article data
file_path = var_functions.query_db:5
with open(file_path, 'r') as f:
    europe_articles = json.load(f)

# Create year-wise categorization
articles_by_year = {}
for article in europe_articles:
    year = int(article['publication_date'][:4])
    article_id = int(article['article_id'])
    if year not in articles_by_year:
        articles_by_year[year] = []
    articles_by_year[year].append(article_id)

years = sorted(articles_by_year.keys())

print('__RESULT__:')
print(json.dumps({
    'years': years,
    'articles_per_year': {year: len(ids) for year, ids in articles_by_year.items()}
}))"}
